                    new DialogueChoice { text = "\"The harvest-fever isn't a plague, Sallow. It's the soul thinning. You can't catch it and you can't cure it — so stop hiding and start *comforting*.\"", nextNodeId = "notplague", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 2 } } },
                    new DialogueChoice { text = "\"Stay across the road, then. Some people are just cowards.\"", nextNodeId = "coward", effects = new[] { new FlagClause { key = "companion.varra.approval", op = FlagOp.AddInt, amount = -1 } } },
                }
