            {
                id = "1", speaker = "Justiciar Veld",
                text = "*(He folds gloved hands.)* The doctrine is not cruel, whatever the weak-stomached say. It is *fair.* The faithful are kept; the faithless are sorted to the nothing they chose by their doubt. A clean ledger. A just scale. *(his certainty is total, and somehow more chilling than any zealot's heat.)* And then *you* — a soul that simply *walked out*, unsorted, un-filed, *unaccountable.* Do you understand what you threaten? Not the church's power. The church's *correctness.* If the law of the dead can be *escaped*, then it was never *law*, only custom — and a man who has sent ten thousand doubters to the Wall on the strength of that law would have to consider that he was not a *justiciar* at all. He was a *murderer with good penmanship.* I will not consider that. So you, error, must be the thing in error. Not me. Never me.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 18] \"You're the most frightened man I've ever met. You can't allow the Wall to be wrong, because then everything you've done becomes murder — so you'll burn the whole world to keep your conscience clean.\"", nextNodeId = "frightened", checkAbility = Ability.Wisdom, checkDC = 18, failNodeId = "unmoved" },
                    new DialogueChoice { text = "\"Sister Garrow served forty years and decided the doctrine was incomplete. Was she a murderer with good penmanship too?\"", nextNodeId = "garrow", conditions = new[] { new FlagClause { key = "prologue.garrow_doubt", op = FlagOp.RequireBoolTrue } } },
                    new DialogueChoice { text = "\"I'm not an error, Veld. I'm the audit. And the books don't balance.\"", nextNodeId = "audit" },
                    new DialogueChoice { text = "\"Correct me, then. I'll be fascinated to watch a clean ledger try to file a hole.\"", nextNodeId = "defiant", effects = new[] { new FlagClause { key = "faction.kelemvor", op = FlagOp.AddInt, amount = -3 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "frightened", speaker = "Justiciar Veld",
                text = "*(For one instant — one — the serene certainty *cracks*, and underneath it is a terror so vast it has needed forty years of doctrine to contain it. Then it seals over, harder than before.)* ...You will not say that to me again. *(very quietly, and it is the quiet of a man holding a door shut against a flood.)* You think you've found my *fear.* You've found my *load-bearing wall.* Pull it, and yes — ten thousand souls become ten thousand murders, and the just justiciar becomes the worst mass-murderer in the history of the Sword Coast, and I cannot — I *will* not — *(his gloved hands have begun to shake; he stills them by force.)* So I will keep the Wall *correct*, error, by whatever means, not because I am cruel, but because the alternative is a truth no mind can survive holding. *(coldly.)* You imagine that makes me weak. It makes me the most *dangerous* man you will meet before the Court of the Dead. A frightened man defending his soul will do what a cruel man never dares.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.veld_loadbearing_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act1.veld_dangerous", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "garrow", speaker = "Justiciar Veld",
                text = "*(His jaw tightens at the name.)* Garrow. *(coldly.)* Garrow was *weak.* She held a sorting in her hands, felt a moment's womanish doubt, and chose her *comfort* over the *law.* *(but something flickers.)* ...She was also, I will grant, the finest grave-warden the order produced in a generation, and she buried more Faithless with reverence than any priest who agreed with the doctrine. *(the flicker hardens back to ice.)* Which makes her *worse*, not better. A fool who doubts the law is merely a fool. A *saint* who doubts it is a *contagion* — she makes the doubt look *holy.* *(he fixes you.)* That is why I'd sooner correct her than you. You're an error. She's a *heresy with clean hands*, and clean hands spread it. Tell your priest the Justiciar remembers her. Tell her I pray she's wrong. *(quietly.)* I pray very hard. It does not help.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.veld_fears_garrow", op = FlagOp.SetTrue }, new FlagClause { key = "sq.garrow_quest_hinted", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "audit", speaker = "Justiciar Veld",
                text = "*(The word lands precisely where it's aimed — on a man who lives by ledgers.)* An *audit.* *(he goes still.)* You choose your metaphor well, error. An audit cannot be *argued* with — only *passed* or *failed.* *(coldly.)* And you stand there implying the church's books, forty centuries closed, do not *balance.* *(a long, dangerous pause.)* Here is the difficulty with your metaphor: an auditor who finds a ten-thousand-soul discrepancy does not get *thanked.* The institution does not *correct itself.* It *discredits the auditor.* *(he turns to go.)* You will find, Returned, that a clean ledger does not fear the truth — it fears the *witness.* And institutions have buried more witnesses than the Wall has doubters. *(at the door.)* Pass your audit if you can. But know that the books were never meant to balance. They were meant to *close.* And I am the man who closes them.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.veld_the_auditor_warning", op = FlagOp.SetTrue }, new FlagClause { key = "act1.veld_dangerous", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "defiant", speaker = "Justiciar Veld",
                text = "*(A thin, cold smile — the first expression he's allowed himself.)* File a hole. *(quietly.)* Yes. That is precisely the problem you represent, stated with vulgar accuracy. The ledger has no column for you. *(he inclines his head.)* So I will not try to file you, error. I will try to *erase* you — which, you'll note, is the one operation the Wall was built to perform. *(he steps back.)* Run along. Gather your heretic priest and your thieves and your damned tiefling. Build your little discrepancy. *(the cold smile widens by a hair.)* And when you reach the end, you will find me there, with my clean ledger and my clean hands and my forty centuries of *correctness*, waiting to close the books on you the way I have closed them on ten thousand doubters who also thought they were the *audit.* They were all just *errors* in the end. So are you.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.veld_enemy", op = FlagOp.SetTrue }, new FlagClause { key = "faction.kelemvor", op = FlagOp.AddInt, amount = -2 }, new FlagClause { key = "act1.veld_dangerous", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "unmoved", speaker = "Justiciar Veld",
                text = "*(Your read glances off the armor of his certainty entirely.)* A clumsy attempt at the alienist's trade. *(coolly.)* I am not *frightened*, error. I am *correct.* The two are easily confused by those who have never had the courage of a settled conviction. *(he turns away.)* Come back when you've a sharper instrument than amateur psychology. The doctrine has withstood subtler attacks than yours for forty centuries. It will withstand a warm corpse with opinions.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Justiciar Veld",
                text = "*(He departs without hurry, serene and unbending — and you understand that of all the powers arrayed in this city, the most dangerous is not the heretic who weeps, nor the devil who hopes, but the just man who *cannot afford to be wrong*, and will unmake the world before he'll examine his own clean hands.)*",
            });

            NpcGateVeldDialogue = g;
        }

        private void BuildNpcGateGlasswidowDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.gate.glasswidow";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Senna the Glassblower",
                text = "*(A woman amid the wreckage of colored glass, patiently sorting shards by hue, a half-built window of impossible beauty leaning against the wall behind her — a window full of small, ordinary faces.)* Mind the glass, love, it gets everywhere when they smash it. *(she holds a shard to the light — a fragment of a child's painted face.)* Third time now. I build the window, the church sends men to break it, I sweep up, I build it again. *(she says it without heat, the way you describe weather.)* It's a memorial, see. For the harvest-dead. The *Faithless* ones — the forgotten ones. I put their faces in glass so the light comes through them of a morning. The church calls it heresy. I call it a window. We've agreed to disagree, them with hammers, me with patience.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.glasswidow_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Senna the Glassblower",
                text = "*(She fits a shard back into the lead.)* My husband was a glassblower. Faithful as the dawn, prayed twice daily, and *still* — *(she shrugs)* — still sorted to the Wall, because the harvest doesn't check your devotion, love, it just takes who's *near.* *(her hands don't stop working.)* So the church can't even claim he *doubted.* He believed every word, and they walled him anyway, and then they send men to smash the window where I painted his face. *(she finally looks at you.)* That's the part I can't make my peace with. Not the smashing. The *contradiction.* They say the Wall's for doubters. My Edmun never doubted a day. So either the Wall lies — or the church does — and either way, somebody owes me a window that *stays whole.*",
                choices = new[]
                {
                    new DialogueChoice { text = "\"I'll guard the window. Let the church send their men. They'll find me first.\"", nextNodeId = "guard", effects = new[] { new FlagClause { key = "sq.glasswidow_window", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 5 } } },
                    new DialogueChoice { text = "[INSIGHT 16] \"You don't rebuild it for Edmun. You rebuild it because each time they smash it and you build it again, *you're* the proof their forgetting doesn't work.\"", nextNodeId = "proof", checkAbility = Ability.Wisdom, checkDC = 16, failNodeId = "patient" },
                    new DialogueChoice { text = "\"Your husband's a contradiction the church can't survive. Let me take his story to people who can use it.\"", nextNodeId = "contradiction", effects = new[] { new FlagClause { key = "faction.kelemvor", op = FlagOp.AddInt, amount = -2 } } },
                    new DialogueChoice { text = "\"Maybe stop rebuilding, Senna. Grief shouldn't be a war of attrition with hammers.\"", nextNodeId = "stop" },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "guard", speaker = "Senna the Glassblower",
                text = "*(She sets down her work, and for the first time her composure wavers.)* You'd — guard it. *(quietly.)* Three times I've swept up alone, love. Three times. And the worst of it isn't the smashing, it's the *next morning*, the light coming through the *empty frame* where the faces should be. *(she wipes her hands.)* If you stood watch — if the window got to *stay*, just once, just long enough for the morning light to come through Edmun's face the way I built it to — *(her voice catches)* — I think I could finally stop. Not stop *remembering.* Stop *fighting.* Let it just be a window, and a morning, and a face in the light, the way a memorial's meant to be. *(fiercely grateful.)* Guard it. And come at dawn. You should see it at dawn. Everyone should. That's the whole point of glass — it only works when the light's allowed through.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.glasswidow_guarded", op = FlagOp.SetTrue }, new FlagClause { key = "sq.glasswidow_window", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "proof", speaker = "Senna the Glassblower",
                text = "*(Her hands go still.)* ...You see it. *(quietly.)* Aye. Edmun's gone; a window won't bring him back; I'm not a fool, love, I know glass from a husband. *(she looks at the half-built faces.)* But every time they smash it and I build it *again* — that's me saying *no.* That's me being the thing their forgetting can't finish. They've got hammers and a god and forty centuries; I've got patience and sand and fire. *(a small, fierce smile.)* And do you know what, love? *I'm winning.* Because they have to send men *every time*, and I only have to be *stubborn*, and stubbornness is cheaper than hammers in the long run. *(she resumes working.)* The window's not a memorial to Edmun. It's a memorial to *not stopping.* Every shard I set back is a little war won against the nothing. Let them smash it. I've sand enough to outlast their arms.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.glasswidow_defiance", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "contradiction", speaker = "Senna the Glassblower",
                text = "*(She considers, then nods slowly.)* Edmun's story. *(quietly.)* A faithful man, walled like a doubter. *(she hands you a shard — his painted eye, catching the light.)* Take it. Show it about. Let the Justiciar explain how a man who prayed twice daily ended in the nothing reserved for *unbelievers.* *(her jaw sets.)* Either the Wall takes the faithful too — in which case their whole *doctrine's* a lie — or the harvest doesn't *care* about faith at all, just *proximity* — in which case the church is sorting people by *bad luck* and calling it *justice.* *(fiercely.)* Both truths are fatal to them, love. My Edmun's quiet death is a *bomb*, and they know it, which is why they smash his face before the morning light can ask the question. *(she meets your eyes.)* Go ask it. Loudly. In daylight. Where the glass would have.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.glasswidow_edmun_proof", op = FlagOp.SetTrue }, new FlagClause { key = "sq.glasswidow_window", op = FlagOp.SetTrue }, new FlagClause { key = "faction.kelemvor", op = FlagOp.AddInt, amount = -1 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "stop", speaker = "Senna the Glassblower",
                text = "*(She shakes her head, gently, fitting another shard.)* Stop. *(quietly.)* Love, the day I stop is the day they *win* — not the day my grief ends. *(she holds a fragment to the light.)* Grief that gives up isn't peace. It's just a quieter kind of forgetting, and forgetting's the whole weapon they're using. *(she almost smiles.)* You're kind to worry about my arms. But a memorial that *survives* is worth a hundred hours of sweeping. And besides — *(she nods at the half-built faces)* — Edmun blew glass for thirty years. He'd be *appalled* if I let a few men with hammers out-stubborn me. It'd be an insult to the craft. No. I'll build it till it stays. That's not a war of attrition, love. That's just *love*, with a longer timeline than the church expected.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.glasswidow_persists", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "patient", speaker = "Senna the Glassblower",
                text = "*(She just smiles, fitting shards.)* You're sweet to theorize, love. But it's simpler than all that. It's a window. It's my husband's face. The light should come through it of a morning. *(she shrugs.)* Everything else is the church's complication, not mine. Mind the glass on your way.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Senna the Glassblower",
                text = "*(She fits another painted face back into the lead — patient, unhurried, unbeatable — and you carry away the certainty that the church can send a thousand men with hammers and still lose to one widow with sand, fire, and a longer timeline than any institution ever reckons on.)*",
            });

            NpcGateGlasswidowDialogue = g;
        }

        private void BuildNpcGateFerrymanDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.gate.ferryman";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "The Ferryman",
                text = "*(An old man at a black skiff where the docks meet the dark water, a pole in his hands and a tin cup at his feet with a single coin in it.)* Passage? *(he doesn't look up.)* The toll's a coin. Always been a coin. Across the Chionthar in the daylight — that's the *honest* crossing, copper'll do. *(now he looks at you, and his eyes are very tired.)* But you're not here for the daylight crossing, are you. You've the look of the *other* fare. The ones who come at dusk with no breath and no coin, because the harvest doesn't leave you time to fetch your purse. *(he taps the tin cup.)* One coin in there. One. In a season of the breathless dead. You do the arithmetic.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.ferryman_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Ferryman",
                text = "*(He poles the skiff a little against the current, holding station.)* I've ferried this river sixty years. Used to be a clean trade — coin in the cup, soul on the far bank, no questions, Kelemvor's own arrangement. *(quietly.)* Then the harvest came, and now the dead arrive *poor*, arrive *robbed of the moment to prepare*, arrive with no coin because they died mid-sentence, mid-meal, mid-laugh. *(he looks at the cup.)* And the rule's the rule: no coin, no crossing. They have to *wait* on the near bank. And the near bank, lately — *(he swallows)* — the near bank is where the harvesters come to *finish* them. Sort them to the Wall before they ever reach the far shore. *(he meets your eyes.)* So I've a choice every dusk, friend. Keep the rule and let them be taken. Or break it, and ferry the coinless free — and answer to a god for the tolls I never collected.",
                choices = new[]
                {
                    new DialogueChoice { text = "\"Ferry them free. I'll answer to the god with you, if it comes to that.\"", nextNodeId = "free", effects = new[] { new FlagClause { key = "sq.ferryman_free", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 5 } } },
                    new DialogueChoice { text = "[INSIGHT 15] \"You've already been ferrying them free. The single coin in the cup is the last honest toll you took — you keep it there to remember when the rule still made sense.\"", nextNodeId = "lastcoin", checkAbility = Ability.Wisdom, checkDC = 15, failNodeId = "rule" },
                    new DialogueChoice { text = "\"Whose rule is it, that the poor wait on the bank to be harvested? Kelemvor's — or the church's?\"", nextNodeId = "whoserule" },
                    new DialogueChoice { text = "\"Keep the rule, old man. A ferryman who breaks his toll is just a thief with a boat.\"", nextNodeId = "keep", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = -2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "free", speaker = "The Ferryman",
                text = "*(The pole stills in the dark water. For a long moment the old man just breathes.)* You'd stand on the far bank and answer for it. *(quietly.)* Sixty years I've waited for someone to say that. Sixty years I've told myself the rule was *Kelemvor's*, that breaking it damned me, that the coinless *had* to wait — *(his voice roughens)* — and every dusk I've watched the harvesters take the ones who couldn't pay, and called my cowardice *piety.* *(he plants the pole, decision made.)* No more. From tonight the skiff runs free at dusk. Coin or no coin. Let the god dock me my tolls; I'll cross every breathless pauper on this river before I'll watch one more sorted on my own near bank. *(fiercely.)* And if Kelemvor asks me why — I'll say a dead thing with no coin of its own offered to share my damnation, and I was *ashamed* to have feared it so long. Get aboard, friend. We've a river of the unpaid waiting, and a long night to ferry them.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ferryman_runs_free", op = FlagOp.SetTrue }, new FlagClause { key = "sq.ferryman_free", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "lastcoin", speaker = "The Ferryman",
                text = "*(His hand goes to the tin cup, protective.)* ...You see it. The one coin. *(quietly.)* Aye. I've been crossing the coinless free for two months. Couldn't not. *(he touches the single copper.)* This is the last *honest* toll I took — from an old woman who *had* a coin, who pressed it on me with both hands and said \"for the ones who can't,\" and died across the river at peace. *(his voice cracks.)* I keep it in the cup so I remember there was a time the rule and the *right* were the same thing. Before the harvest made the toll a *trap.* *(he looks at the dark water.)* You're the first to notice it's only the one. Everyone else sees an empty trade and a tired old man. You saw the *coin.* *(quietly.)* Then you understand. The rule's not gone — it's just become a thing the kind have to break to *keep.* Ride free, friend. You've already paid, in the only currency left: you *looked.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ferryman_already_free", op = FlagOp.SetTrue }, new FlagClause { key = "sq.ferryman_free", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 2 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "whoserule", speaker = "The Ferryman",
                text = "*(He frowns at the water, an old question surfacing.)* Whose rule. *(slowly.)* I always said Kelemvor's. \"A coin for the crossing\" — it's old, it's *holy*, it's in the oldest rites. *(he scratches his chin.)* But the *waiting* — the bit where the coinless have to *linger* on the near bank, where the harvesters can reach them — *(his eyes narrow)* — that's *new.* That came in with the harvest. With the *church's* new orders, not the god's old rite. *(quietly, a realization dawning.)* Kelemvor's rule was *a coin for the crossing.* The *church* added *and the coinless wait* — and put the harvesters where the waiting happens. *(he grips the pole.)* So it was never the god damning the poor. It was the *church*, using the god's old toll as a *snare.* *(fiercely.)* Sixty years I feared the wrong master. The god never said let them be taken. The *church* did. ...That changes everything about which rule I'm breaking, friend. Thank you. I'll break the church's gladly. The god's, I'll keep. And I suspect the god will thank me for telling them apart.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ferryman_sees_the_snare", op = FlagOp.SetTrue }, new FlagClause { key = "sq.ferryman_free", op = FlagOp.SetTrue }, new FlagClause { key = "act1.choir_doubt_seeded", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "keep", speaker = "The Ferryman",
                text = "*(He nods, slowly, and something in him dims.)* A thief with a boat. *(quietly.)* Aye. Perhaps that's all a ferryman who breaks his toll becomes. *(he looks at the near bank, where dusk is gathering.)* So I'll keep the rule, and the coinless will wait, and the harvesters will come, and I'll tell myself it's *piety* and not *fear*, same as I've told myself for two months. *(he poles the skiff.)* You're not wrong, friend. A rule's a rule. *(but he won't look at the near bank now.)* ...Mind the step. The honest crossing's a copper. The other one — the other one I'm apparently still letting the dark water decide.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ferryman_keeps_rule", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "rule", speaker = "The Ferryman",
                text = "*(He shakes his head, your read missing the mark.)* No, friend, the rule's the rule, simple as that — coin for the crossing, sixty years. *(but his hand rests on the tin cup a beat too long.)* ...The single coin's just slow business. Nothing more. *(he poles away from the question.)* Copper for the daylight crossing, if that's what you're after. The dusk fare's between me and the river.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Ferryman",
                text = "*(He poles the black skiff out toward the failing light, an old man at the exact seam between the god's mercy and the church's snare — and whether he runs free tonight or keeps his lonely rule, you carry away the image of one copper in a tin cup, kept against the memory of a time when the toll and the kindness were the same coin.)*",
            });

            NpcGateFerrymanDialogue = g;
        }
    }
}
